/* Reasoning GP — Articles data (batch 8: D topics)
   RCGP/SCA examiner depth. NICE NG12 (May 2025) 2WW pathways stated explicitly where relevant. */
(function(){
  const A = (window.RGP_ARTICLES = window.RGP_ARTICLES || []);
  A.push(

  { id:'dehydration', title:'Dehydration', category:'General', icon:'💧',
    overview:'A deficit of body water (and often electrolytes) when losses exceed intake. It ranges from mild and easily corrected to life-threatening hypovolaemia. The extremes of age are most vulnerable, and the priorities are assessing severity, identifying the cause, and rehydrating by the safest effective route.',
    features:[
      'Symptoms: thirst, dry mouth, reduced/dark urine, lightheadedness, fatigue and (in children) reduced wet nappies',
      'Signs of increasing severity: tachycardia, hypotension/postural drop, prolonged capillary refill, reduced skin turgor, sunken eyes, and (late) confusion, lethargy and oliguria',
      'Common causes: gastroenteritis (vomiting/diarrhoea), fever, poor intake (frailty, dementia), heat, diabetes (osmotic diuresis/DKA), and excessive diuretics',
      'Infants, young children and frail older adults decompensate quickly and are the highest-risk groups',
      'In children, assess using clinical dehydration scales and watch for "red flag" signs and shock',
      'Investigations where needed: U&E (urea, sodium, kidney function), glucose, and assessment for the underlying cause'],
    management:[
      'Identify and treat the cause while correcting the fluid deficit',
      'Mild–moderate dehydration: oral rehydration is preferred — encourage fluids, and use oral rehydration solution (ORS) especially in children and with ongoing GI losses',
      'Give small, frequent amounts of ORS in vomiting children; continue breastfeeding',
      'Severe dehydration/shock, or inability to tolerate oral fluids: IV fluid resuscitation in hospital',
      'Monitor response (urine output, observations, weight in children) and electrolytes; correct sodium disturbances carefully to avoid rapid shifts',
      'Review and temporarily adjust medications that worsen dehydration (e.g. diuretics, ACE inhibitors, NSAIDs — "sick-day rules") and prevent acute kidney injury',
      'Safety-net: advise on warning signs and when to seek urgent help',
      'Prevent recurrence: address frailty/intake, heat exposure, and chronic causes'],
    referral:[
      'Severe dehydration, shock, or inability to tolerate oral fluids → emergency admission for IV rehydration',
      'Children with red-flag dehydration signs or unsafe home circumstances → urgent paediatric assessment',
      'Significant electrolyte disturbance or acute kidney injury → urgent assessment',
      'Underlying cause needing specialist input (e.g. DKA, persistent vomiting) → relevant pathway'],
    source:'NICE NG29 (IV fluids) / NICE CKS — Gastroenteritis' },

  { id:'frontotemporal-dementia', title:'Frontotemporal dementia', category:'Neurology', icon:'🧠',
    overview:'A group of dementias from progressive degeneration of the frontal and temporal lobes, typically with younger onset (often 45–65) than Alzheimer’s. Memory is relatively preserved early; the hallmark is change in behaviour/personality or in language, which is frequently mistaken for a psychiatric disorder.',
    features:[
      'Behavioural variant: early, striking personality and behaviour change — disinhibition, apathy, loss of empathy, compulsive/ritualistic behaviours, and changes in eating (often a craving for sweet foods)',
      'Language variants (primary progressive aphasia): progressive difficulty with speech production or word/object meaning, with relatively preserved memory early on',
      'Relatively preserved episodic memory and spatial skills early — a contrast with Alzheimer’s',
      'Younger onset than typical Alzheimer’s; a family history is more common (some genetic forms)',
      'Overlap with motor neurone disease and atypical parkinsonian syndromes in some patients',
      'Diagnosis: specialist cognitive/neuropsychological assessment and imaging (frontal/temporal atrophy); often initially misdiagnosed as depression or a personality/psychiatric disorder'],
    management:[
      'Consider FTD in younger patients with prominent personality/behaviour change or progressive language difficulty, even when memory seems intact',
      'Take a collateral history and screen for/treat reversible contributors; refer to a (often younger-onset/cognitive) specialist memory or neurology service',
      'There is no disease-modifying drug, and acetylcholinesterase inhibitors are NOT recommended (may worsen behaviour); memantine is not routinely used',
      'Manage behavioural symptoms primarily with non-pharmacological strategies and environmental/behavioural approaches and carer support',
      'Use psychotropic medication cautiously and only when needed for severe distress/risk, at the lowest effective dose with review',
      'Provide strong carer support and education — behavioural FTD is especially challenging for families',
      'Address risk, safeguarding, capacity, driving (advise DVLA notification), finances and advance care planning early while capacity allows',
      'Coordinate multidisciplinary support and plan for progression'],
    referral:[
      'Suspected FTD (younger-onset behaviour/personality change or progressive aphasia) → specialist cognitive/neurology service (ideally younger-onset dementia service)',
      'Diagnostic uncertainty or overlap with motor neurone disease/parkinsonism → neurology',
      'Severe behavioural disturbance or risk → old-age/younger-onset psychiatry',
      'Complex social, capacity, or safeguarding needs → appropriate services'],
    source:'NICE NG97 (Dementia)' },

  { id:'vascular-dementia', title:'Vascular dementia', category:'Neurology', icon:'🧠',
    overview:'The second commonest dementia, caused by cerebrovascular disease — from strategic infarcts or, more often, accumulated small-vessel disease. It frequently coexists with Alzheimer’s ("mixed dementia"). Because it shares risk factors with stroke, vascular risk-factor control is central to prevention and slowing progression.',
    features:[
      'Cognitive decline with prominent executive dysfunction and slowed processing, often with relatively preserved early memory compared with Alzheimer’s',
      'Classic "stepwise" deterioration after vascular events, though small-vessel disease often causes a more gradual decline',
      'Focal neurological signs, gait disturbance/falls, and mood changes (depression, emotional lability) are common',
      'Strong vascular risk-factor burden: hypertension, diabetes, atrial fibrillation, hyperlipidaemia, smoking, and previous stroke/TIA',
      'Often coexists with Alzheimer’s pathology (mixed dementia)',
      'Diagnosis: cognitive assessment, vascular risk evaluation, and neuroimaging (CT/MRI showing infarcts/small-vessel changes)'],
    management:[
      'Take a collateral history, assess cognition and function, and exclude reversible contributors',
      'Refer to the memory-assessment service for diagnosis and subtyping',
      'Aggressively optimise vascular risk factors — this is the cornerstone: treat hypertension, diabetes and hyperlipidaemia, manage atrial fibrillation/anticoagulation, support smoking cessation, and promote exercise and a healthy diet',
      'Acetylcholinesterase inhibitors/memantine are not recommended for pure vascular dementia but may be used if there is coexisting Alzheimer’s/Lewy body/Parkinson’s dementia',
      'Provide non-pharmacological support: cognitive stimulation, structured care, carer education and respite',
      'Treat comorbid depression and manage behavioural symptoms non-pharmacologically first',
      'Address driving (advise DVLA notification), safeguarding, capacity, power of attorney and advance care planning',
      'Provide a named contact, written information and regular review; plan ahead for progression'],
    referral:[
      'Suspected dementia → memory-assessment/diagnostic service',
      'Younger-onset, rapid progression, or diagnostic uncertainty → specialist neurology/old-age psychiatry',
      'Acute focal neurology/suspected stroke or TIA → urgent stroke/TIA pathway',
      'Severe behavioural disturbance or risk → old-age psychiatry'],
    source:'NICE NG97 (Dementia)' },

  { id:'lewy-body-dementia', title:'Dementia with Lewy bodies', category:'Neurology', icon:'🧠',
    overview:'A common dementia caused by alpha-synuclein (Lewy body) pathology, with a characteristic triad of fluctuating cognition, recurrent visual hallucinations and spontaneous parkinsonism. Recognising it is critical because of a dangerous severe sensitivity to antipsychotic drugs.',
    features:[
      'Fluctuating cognition with pronounced variations in attention and alertness',
      'Recurrent, well-formed, detailed visual hallucinations (often of people or animals)',
      'Spontaneous parkinsonism (bradykinesia, rigidity, tremor) — by definition arising around or after cognitive decline (within ~1 year), distinguishing it from Parkinson’s disease dementia',
      'REM sleep behaviour disorder (acting out dreams), often predating dementia by years, and prominent autonomic features (postural hypotension, falls, syncope)',
      'SEVERE NEUROLEPTIC SENSITIVITY: antipsychotics can cause profound, sometimes life-threatening reactions (worsened parkinsonism, sedation, neuroleptic malignant syndrome) — avoid them',
      'Diagnosis is specialist/clinical, supported by imaging (e.g. DaTscan showing reduced dopamine uptake)'],
    management:[
      'Suspect DLB with the core features (fluctuation, visual hallucinations, parkinsonism, REM sleep behaviour disorder) and refer to a specialist memory/neurology service',
      'AVOID antipsychotics wherever possible because of severe neuroleptic sensitivity; if absolutely essential for severe distress/risk, use only under specialist guidance at the lowest dose with very close monitoring',
      'Acetylcholinesterase inhibitors (e.g. rivastigmine, donepezil) are recommended and can improve cognition and hallucinations; memantine may be used',
      'Manage parkinsonism cautiously — dopaminergic drugs can worsen hallucinations, so balance motor and neuropsychiatric symptoms with specialist input',
      'Treat autonomic features (postural hypotension), falls, constipation and REM sleep behaviour disorder, and review sedating/anticholinergic drugs',
      'Provide non-pharmacological management of hallucinations/behaviour and strong carer support',
      'Address driving (DVLA), safeguarding, capacity and advance care planning',
      'Flag the antipsychotic-sensitivity risk prominently in the record to prevent inadvertent harm'],
    referral:[
      'Suspected DLB → specialist memory/neurology service for diagnosis (± DaTscan)',
      'Need for antipsychotic, or severe neuropsychiatric symptoms → specialist (old-age psychiatry) given neuroleptic sensitivity',
      'Complex parkinsonism vs neuropsychiatric trade-offs → neurology/movement disorders',
      'Falls/syncope from autonomic dysfunction → appropriate assessment'],
    source:'NICE NG97 (Dementia)' },

  { id:'dental-abscess', title:'Dental abscess', category:'General', icon:'🦷',
    overview:'A localised collection of pus from a bacterial infection of a tooth or its supporting structures. It is acutely painful and, although usually managed by dental services, can spread to cause serious deep-space infection. The GP role is analgesia, recognising spreading/airway-threatening infection, and directing the patient to definitive dental care.',
    features:[
      'Severe, throbbing toothache, often worse on biting, lying down, or with hot/cold; localised swelling and tenderness',
      'A periapical (from a dead/infected tooth pulp) or periodontal (gum) abscess; sometimes a visible fluctuant swelling or sinus discharging pus',
      'Localised facial/gum swelling, a bad taste, and regional lymphadenopathy',
      'RED FLAGS for spreading infection: significant facial swelling, trismus (difficulty opening the mouth), difficulty swallowing or breathing, swelling of the floor of the mouth (Ludwig’s angina), eye involvement, and systemic sepsis',
      'Definitive treatment is dental (drainage, root canal, or extraction) — antibiotics alone do not cure it',
      'Diagnosis is clinical; dental imaging is part of dental assessment'],
    management:[
      'Direct the patient to urgent dental care for definitive treatment (drainage/root canal/extraction) — this is the curative step',
      'Provide effective analgesia (paracetamol ± ibuprofen) for pain relief while dental treatment is arranged',
      'Antibiotics are NOT needed for a localised dental abscess with no spreading infection or systemic features — emphasise the need for dental treatment instead (antibiotic stewardship)',
      'Prescribe antibiotics (e.g. amoxicillin or metronidazole per guidance) only where there are signs of spreading infection, systemic involvement, or in immunocompromised patients — as an adjunct to, not a substitute for, dental treatment',
      'Advise warm salt-water rinses and good oral hygiene as supportive measures',
      'Recognise and urgently refer spreading/deep-space or airway-threatening infection',
      'Safety-net clearly for increasing swelling, trismus, swallowing/breathing difficulty, or systemic illness',
      'Signpost emergency/out-of-hours dental services and address barriers to dental access'],
    referral:[
      'Spreading infection, trismus, dysphagia, airway compromise, floor-of-mouth/peri-orbital swelling, or systemic sepsis → emergency hospital (maxillofacial/ENT) admission',
      'Localised dental abscess → urgent dental service for definitive treatment',
      'Immunocompromised patient with dental infection → lower threshold for antibiotics and urgent dental/specialist care',
      'Recurrent dental infection → dental review for underlying cause'],
    source:'NICE CKS — Dental abscess' },

  { id:'retinal-detachment', title:'Detached retina (retinal detachment)', category:'Ophthalmology', icon:'👁️',
    overview:'Separation of the neurosensory retina from the underlying retinal pigment epithelium — a sight-threatening emergency. Prompt recognition and same-day referral are vital, because the visual outcome depends on whether the macula is still attached when surgery is performed.',
    features:[
      'New floaters (often a sudden shower) and flashes of light (photopsia) — the classic warning symptoms of a retinal tear/detachment',
      'A "curtain" or shadow spreading across the field of vision, and painless visual loss',
      'Reduced visual acuity if the macula becomes involved ("mac-off")',
      'Risk factors: increasing age, high myopia, previous cataract/eye surgery, eye trauma, and a personal/family history of detachment',
      'Posterior vitreous detachment commonly causes flashes/floaters and can precede or mimic detachment — but cannot be distinguished clinically from a tear without examination',
      'Diagnosis requires urgent ophthalmological examination (dilated fundoscopy); the macula’s status determines urgency'],
    management:[
      'Treat new flashes and floaters, or any field defect/visual loss, as a possible retinal tear/detachment until proven otherwise',
      'Refer same-day to ophthalmology (or send to eye casualty) for urgent assessment — do not delay',
      'Advise the patient to avoid strenuous activity and to seek immediate care if symptoms progress (spreading shadow, worsening vision)',
      'Macula-on detachments need very urgent surgery to preserve central vision; macula-off detachments are still treated promptly but central vision may not fully recover',
      'Treatment is surgical/laser: laser or cryotherapy for tears, and vitrectomy or scleral buckle ± gas/oil for detachment',
      'After treatment, support recovery (e.g. posturing advice for gas tamponade, avoiding air travel with intraocular gas) per the eye team',
      'Counsel on the increased risk in the fellow eye and the importance of reporting new symptoms promptly',
      'Provide clear information and follow-up coordination'],
    referral:[
      'New flashes/floaters, a visual-field "curtain", or sudden painless visual loss → same-day ophthalmology / eye casualty (suspected retinal detachment)',
      'Macula-threatening (macula-on) detachment → very urgent surgical assessment',
      'Posterior vitreous detachment symptoms → urgent ophthalmology to exclude a tear',
      'Any associated ocular trauma → urgent ophthalmology'],
    source:'NICE CKS — Retinal detachment / Royal College of Ophthalmologists' },

  { id:'dyspraxia', title:'Developmental co-ordination disorder (dyspraxia)', category:'Paediatrics', icon:'🧒',
    overview:'A neurodevelopmental disorder of motor co-ordination that is substantially below the expected level for age and not explained by another medical/neurological condition, significantly affecting daily activities and school. It is common, often coexists with other neurodevelopmental conditions, and benefits from early support.',
    features:[
      'Clumsiness and poor motor co-ordination: difficulty with running, jumping, catching, riding a bike, and frequent tripping/bumping',
      'Fine-motor difficulties: handwriting, doing buttons/laces, using cutlery, and other self-care tasks',
      'Difficulty learning new motor skills and with planning/organising movements and tasks',
      'Impact on schoolwork, self-care, play and self-esteem; frustration and avoidance of physical activities',
      'Frequently coexists with ADHD, autism, dyslexia, and speech/language difficulties',
      'Diagnosis is made (usually by paediatrics/occupational therapy) after excluding other causes; motor difficulty is not due to a general medical, neurological or intellectual condition'],
    management:[
      'Take a developmental history, examine to exclude neurological/other causes, and assess the functional impact',
      'Refer for multidisciplinary assessment (community paediatrics/occupational therapy ± physiotherapy) to confirm the diagnosis and guide support',
      'Occupational therapy is central: task-specific training, strategies and adaptations for handwriting, self-care and daily activities',
      'Work with the school for support and reasonable adjustments (e.g. extra time, assistive technology, seating, PE adaptations) and an education plan where needed',
      'Encourage participation in physical activity to build skills and confidence; break tasks into steps and practise',
      'Identify and address coexisting conditions (ADHD, autism, dyslexia, anxiety)',
      'Support self-esteem and mental wellbeing, which are commonly affected',
      'Provide information to families and signpost support; arrange review of progress'],
    referral:[
      'Suspected developmental co-ordination disorder → community paediatrics / occupational therapy assessment',
      'Coexisting neurodevelopmental concerns (ADHD, autism, learning difficulties) → relevant assessment pathway',
      'Significant functional/educational impact → educational support / SEN processes',
      'Any neurological red flags (regression, focal signs) → urgent paediatric/neurology assessment'],
    source:'NICE CKS / paediatric neurodevelopmental guidance' },

  { id:'gestational-diabetes', title:'Gestational diabetes', category:'Women’s health', icon:'🤰',
    aka:'Diabetes in pregnancy',
    overview:'Carbohydrate intolerance first recognised in pregnancy, caused by the diabetogenic hormonal milieu. It increases risks to mother and baby (macrosomia, shoulder dystocia, neonatal hypoglycaemia, pre-eclampsia) but these are reduced by good glycaemic control. It also flags a high future risk of type 2 diabetes.',
    features:[
      'Usually asymptomatic and detected by screening — risk-factor-based oral glucose tolerance testing (OGTT) at around 24–28 weeks (earlier with previous GDM)',
      'Risk factors: BMI >30, previous GDM, previous macrosomic baby (≥4.5 kg), family history of diabetes, and certain higher-risk ethnic backgrounds',
      'Maternal risks: pre-eclampsia, polyhydramnios, increased intervention/operative delivery, and progression to type 2 diabetes',
      'Fetal/neonatal risks: macrosomia, shoulder dystocia/birth injury, neonatal hypoglycaemia, jaundice, and (with pre-existing diabetes) congenital anomaly',
      'Distinguish from pre-existing (type 1/2) diabetes in pregnancy, which carries first-trimester and higher overall risk',
      'Diagnosis per NICE thresholds on OGTT (fasting ≥5.6 mmol/L or 2-hour ≥7.8 mmol/L)'],
    management:[
      'Refer promptly to the joint diabetes-antenatal team for multidisciplinary care',
      'First-line is lifestyle: dietary advice (carbohydrate quality/quantity), physical activity, and blood-glucose self-monitoring against pregnancy targets',
      'If glucose targets are not met with diet/exercise within 1–2 weeks, add metformin; offer insulin if metformin is insufficient/unsuitable (and consider insulin from the outset if glucose is high or there is macrosomia/polyhydramnios)',
      'Monitor fetal growth and wellbeing; plan timing and mode of birth with the obstetric team',
      'Ensure good intrapartum glucose control and anticipate/manage neonatal hypoglycaemia',
      'Stop glucose-lowering treatment after birth (GDM usually resolves) and check maternal glucose before discharge',
      'Arrange postnatal follow-up: a fasting glucose/HbA1c at ~6–13 weeks, then annual diabetes screening — and counsel on the high lifetime type 2 diabetes risk and prevention',
      'Advise pre-pregnancy planning/early testing in future pregnancies'],
    referral:[
      'Diagnosed gestational diabetes → joint diabetes-antenatal clinic',
      'Pre-existing diabetes in pregnancy, or very high glucose at diagnosis → specialist obstetric-diabetes care (and pre-pregnancy optimisation where possible)',
      'Fetal concerns (macrosomia, polyhydramnios) or maternal complications (pre-eclampsia) → obstetric review',
      'Postnatal: persistent hyperglycaemia → diabetes services'],
    source:'NICE NG3 (Diabetes in pregnancy)' },

  { id:'diabetes-insipidus', title:'Diabetes insipidus (arginine vasopressin disorders)', category:'Endocrine & metabolic', icon:'💧',
    overview:'A disorder of water balance from deficiency of (cranial/central) or resistance to (nephrogenic) antidiuretic hormone (ADH/AVP), causing the production of large volumes of dilute urine and intense thirst. It is unrelated to diabetes mellitus. The danger is rapid dehydration and hypernatraemia if water access or thirst is impaired.',
    features:[
      'Polyuria (large volumes of dilute urine, including nocturia) and intense, persistent thirst (polydipsia)',
      'Cranial (central) DI: deficient ADH — causes include pituitary/hypothalamic tumours or surgery, trauma, infiltrative disease, and idiopathic/autoimmune',
      'Nephrogenic DI: renal resistance to ADH — causes include lithium, hypercalcaemia, hypokalaemia, chronic kidney disease, and genetic forms',
      'Risk of severe dehydration and hypernatraemia, especially if thirst is impaired or fluid access is limited (e.g. unconscious, frail, very young)',
      'Differentials: diabetes mellitus (check glucose), primary polydipsia, and diuretic use',
      'Diagnosis: exclude diabetes mellitus, confirm dilute urine with high serum osmolality, and use a water-deprivation test ± desmopressin to localise (cranial vs nephrogenic), with MRI for central causes'],
    management:[
      'Exclude diabetes mellitus and other causes of polyuria first (glucose, U&E including calcium/potassium, urine osmolality)',
      'Refer to endocrinology for diagnosis (water-deprivation/desmopressin testing) and to identify the underlying cause',
      'Cranial DI: treat with desmopressin (an ADH analogue), titrated carefully to avoid hyponatraemia from over-treatment',
      'Nephrogenic DI: treat the cause where possible (e.g. review lithium, correct hypercalcaemia/hypokalaemia); management includes adequate fluid intake, a low-salt/low-protein diet, and thiazide diuretics ± other agents',
      'Ensure free access to water and educate the patient on the risk of dehydration during illness/reduced intake',
      'Monitor serum sodium and fluid balance, particularly when initiating/adjusting desmopressin',
      'Flag the diagnosis clearly (especially around surgery/illness/inpatient stays) to prevent dangerous fluid mismanagement and missed desmopressin doses',
      'Investigate and follow up central causes (pituitary imaging, anterior pituitary function)'],
    referral:[
      'Suspected diabetes insipidus → endocrinology for confirmation and treatment',
      'Suspected pituitary/hypothalamic lesion → endocrinology/neurosurgery (pituitary MRI)',
      'Severe dehydration/hypernatraemia → emergency admission',
      'Lithium-induced or other nephrogenic DI → review cause ± nephrology/endocrinology'],
    source:'NICE CKS / Society for Endocrinology (AVP disorders)' },

  { id:'dka', title:'Diabetic ketoacidosis (DKA)', category:'Endocrine & metabolic', icon:'🩸',
    overview:'A life-threatening acute complication of (usually type 1) diabetes from absolute insulin deficiency, causing hyperglycaemia, ketosis and metabolic acidosis. It can be the first presentation of type 1 diabetes — so recognising it in primary care and arranging immediate admission saves lives.',
    features:[
      'Polyuria, polydipsia, weight loss, then nausea/vomiting, abdominal pain, and lethargy',
      'Signs: dehydration, deep sighing (Kussmaul) breathing, a ketotic (pear-drop/acetone) smell on the breath, tachycardia, hypotension, and reduced consciousness',
      'Biochemical triad: hyperglycaemia (or known diabetes), ketonaemia/ketonuria, and acidosis',
      'Common precipitants: infection, missed/insufficient insulin, new-onset type 1 diabetes, and acute illness; SGLT2 inhibitors can cause euglycaemic DKA',
      'Beware euglycaemic DKA (near-normal glucose with ketosis/acidosis), particularly on SGLT2 inhibitors',
      'It can be the first presentation of type 1 diabetes — especially in children/young adults with a short history of osmotic symptoms and weight loss'],
    management:[
      'Suspect DKA in any unwell person with diabetes (or new osmotic symptoms with weight loss) and check capillary glucose and blood/urine ketones immediately',
      'DKA is a medical emergency — arrange immediate hospital admission for IV fluids, fixed-rate insulin infusion, and electrolyte (especially potassium) management',
      'Do not delay admission to do extensive primary-care work-up; give whatever supportive care is appropriate while arranging transfer',
      'Identify and treat the precipitant (e.g. infection)',
      'In known diabetes, reinforce "sick-day rules": never stop insulin, monitor glucose and ketones during illness, maintain fluids, and seek help early',
      'Educate on ketone testing and when to escalate; ensure access to ketone meters/strips',
      'For SGLT2 inhibitor users, advise on euglycaemic DKA risk and sick-day guidance (consider withholding during acute illness)',
      'After recovery, review insulin regimen, education and support to prevent recurrence'],
    referral:[
      'Suspected DKA → immediate emergency admission',
      'New-onset type 1 diabetes (especially with ketones) → same-day specialist/paediatric admission',
      'Recurrent DKA → diabetes specialist team (education, psychosocial support, regimen review)',
      'Euglycaemic DKA on SGLT2 inhibitor → emergency admission and review the drug'],
    source:'JBDS DKA guideline / NICE NG17 & NG18' },

  { id:'diabetic-retinopathy', title:'Diabetic retinopathy', category:'Ophthalmology', icon:'👁️',
    overview:'Progressive microvascular damage to the retina from chronic hyperglycaemia — a leading cause of preventable blindness in working-age adults. It is usually asymptomatic until advanced, which is why systematic screening and good metabolic control are the key preventive interventions.',
    features:[
      'Typically asymptomatic until sight-threatening — hence the importance of annual retinal screening for everyone with diabetes',
      'Background/non-proliferative retinopathy: microaneurysms, dot/blot haemorrhages, exudates and cotton-wool spots',
      'Proliferative retinopathy: new vessel formation (neovascularisation) that can bleed (vitreous haemorrhage) or cause tractional retinal detachment — sight-threatening',
      'Diabetic maculopathy: macular oedema/exudates threatening central vision — the commonest cause of visual loss in type 2 diabetes',
      'Symptoms when present: blurred/fluctuating vision, floaters (haemorrhage), or sudden visual loss',
      'Risk factors: duration of diabetes, poor glycaemic and blood-pressure control, dyslipidaemia, pregnancy, and renal disease'],
    management:[
      'Ensure every patient with diabetes is enrolled in and attends the national Diabetic Eye Screening Programme (annual digital retinal photography)',
      'Optimise the modifiable drivers in primary care: tight glycaemic control (HbA1c), blood pressure, and lipids; support smoking cessation',
      'Act on screening results — refer to ophthalmology per the graded outcome (e.g. referable maculopathy or proliferative changes)',
      'Sight-threatening disease is treated by ophthalmology: laser photocoagulation, intravitreal anti-VEGF/steroid injections for macular oedema, and vitrectomy for advanced complications',
      'Arrange additional/early eye review in pregnancy (retinopathy can progress rapidly) and with rapid glycaemic improvement',
      'Advise prompt reporting of new visual symptoms (floaters, sudden loss) between screening visits',
      'Address driving and visual-standards implications where vision is affected',
      'Coordinate holistic diabetes care, as retinopathy reflects overall microvascular risk (screen for nephropathy/neuropathy)'],
    referral:[
      'Screening-detected referable retinopathy/maculopathy or proliferative changes → ophthalmology per programme grading',
      'Sudden visual loss, new significant floaters, or suspected vitreous haemorrhage/retinal detachment → urgent/same-day ophthalmology',
      'Pregnancy in a woman with diabetes → additional retinal screening',
      'Non-attendance at screening → actively encourage and re-refer'],
    source:'NICE NG (diabetes) / NHS Diabetic Eye Screening Programme' },

  { id:'digeorge', title:'DiGeorge syndrome (22q11.2 deletion)', category:'Paediatrics', icon:'🧬',
    overview:'A common chromosomal microdeletion syndrome with highly variable features, classically affecting the heart, parathyroids, thymus (immunity), palate and development. Recognising the pattern matters because of treatable, sometimes dangerous, components — congenital heart disease, hypocalcaemia and immunodeficiency.',
    features:[
      'Congenital heart disease (especially conotruncal defects — tetralogy of Fallot, interrupted aortic arch, VSD)',
      'Hypoparathyroidism → hypocalcaemia (neonatal seizures, tetany, or later symptomatic low calcium)',
      'Thymic hypoplasia → T-cell immunodeficiency and recurrent infections (severity varies; live vaccines may be contraindicated in significant immunodeficiency)',
      'Palatal abnormalities (cleft palate, velopharyngeal insufficiency) causing nasal speech and feeding difficulty',
      'Characteristic facial features, developmental delay/learning difficulties, and a high rate of psychiatric disorders (including a markedly increased risk of schizophrenia in adulthood)',
      'Diagnosis: genetic testing (e.g. microarray/FISH for the 22q11.2 deletion); remember the mnemonic "CATCH-22"'],
    management:[
      'Coordinate care through a multidisciplinary team (paediatrics, cardiology, immunology, ENT/cleft service, endocrinology, genetics, speech and language therapy, and psychiatry/psychology)',
      'Identify and treat congenital heart disease (cardiology/surgery) and monitor calcium — treat hypocalcaemia (calcium/vitamin D/alfacalcidol) and watch for it during illness/surgery',
      'Assess immune function; in significant T-cell immunodeficiency, avoid live vaccines and consider antimicrobial prophylaxis and irradiated blood products — per immunology',
      'Manage palatal/feeding and speech issues with the cleft/SALT services',
      'Support development and education; monitor for and manage mental-health problems (with heightened vigilance for psychosis from adolescence)',
      'Offer genetic counselling for the family (inheritance and recurrence risk)',
      'In primary care, maintain immunisation planning per immunology, recognise hypocalcaemia, and support coordinated follow-up',
      'Provide family information and signpost support'],
    referral:[
      'Suspected 22q11.2 deletion → clinical genetics + relevant specialties (cardiology, immunology, endocrinology)',
      'Congenital heart disease → paediatric cardiology',
      'Immunodeficiency / vaccine and blood-product decisions → immunology',
      'Mental-health symptoms (especially emerging psychosis) → psychiatry'],
    source:'NICE CKS / clinical genetics & immunology guidance' },

  { id:'diphtheria', title:'Diphtheria', category:'Infectious diseases', icon:'🦠',
    overview:'A serious, vaccine-preventable infection caused by toxin-producing Corynebacterium diphtheriae (and related species). Rare in the UK thanks to immunisation, it can cause a life-threatening membranous pharyngitis with airway obstruction and toxin-mediated cardiac and neurological damage. It is a public-health emergency.',
    features:[
      'Respiratory diphtheria: sore throat, fever, and an adherent grey-white pseudomembrane over the tonsils/pharynx that bleeds if removed',
      'A "bull neck" from marked cervical lymphadenopathy and oedema; airway obstruction is the immediate danger',
      'Cutaneous diphtheria: chronic non-healing ulcers (commoner in travellers/people experiencing homelessness)',
      'Toxin-mediated complications: myocarditis (arrhythmia, heart failure) and neuropathy (palatal and peripheral)',
      'Risk: unimmunised/under-immunised individuals and travel to/contact with endemic areas',
      'Diagnosis: clinical suspicion plus throat/lesion swabs for culture and toxigenicity testing — alert the laboratory and public health'],
    management:[
      'Suspect diphtheria in a febrile sore throat with a pharyngeal membrane, especially if unimmunised or with relevant travel/contact',
      'This is a medical and public-health emergency — admit immediately, isolate the patient, and contact UKHSA/health protection urgently',
      'Treatment is with diphtheria antitoxin (to neutralise circulating toxin — given early, before lab confirmation, on clinical suspicion) plus antibiotics (e.g. penicillin or a macrolide)',
      'Protect and support the airway; monitor for and manage myocarditis and neurological complications',
      'Take swabs (alert the lab) but do not delay antitoxin/treatment awaiting results',
      'Public health will manage contact tracing, prophylaxis, vaccination and exclusion',
      'Ensure the patient and contacts are vaccinated (infection does not confer reliable immunity)',
      'Diphtheria is a notifiable disease — report immediately'],
    referral:[
      'Suspected diphtheria → emergency admission (infectious diseases) with immediate UKHSA notification',
      'Airway compromise → emergency airway management',
      'Myocarditis/arrhythmia or neurological complications → urgent specialist (cardiology/neurology) care',
      'Contacts → public-health-led tracing, prophylaxis and vaccination'],
    source:'UKHSA diphtheria guidance / Green Book' },

  { id:'discoid-eczema', title:'Discoid eczema (nummular dermatitis)', category:'Dermatology', icon:'🟠',
    overview:'A distinctive pattern of eczema with well-defined, coin-shaped ("discoid") itchy plaques, typically on the limbs. It is benign but often intensely itchy and chronic/relapsing. The main differential is tinea (ringworm), and lower-leg lesions in older patients can be confused with other conditions.',
    features:[
      'Well-demarcated, round/oval ("coin-shaped") plaques of eczema, often weeping/crusted in acute phases and scaly when chronic',
      'Usually very itchy; commonly on the limbs (legs/arms), trunk and dorsa of the hands',
      'Often dry skin and a relapsing-remitting course; may be triggered by skin dryness, irritants, or stress',
      'Differential: tinea corporis (ringworm — usually with central clearing and an active scaly edge; scrape if in doubt), psoriasis, and Bowen’s disease (a persistent solitary scaly plaque, especially on the lower leg of older patients)',
      'Secondary bacterial infection is common (weeping, crusting, pustules)',
      'Diagnosis is clinical; skin scrapings help exclude tinea, and biopsy is reserved for atypical/persistent solitary lesions'],
    management:[
      'Generous, regular emollients and soap substitutes are the foundation; avoid irritants and keep the skin well moisturised',
      'Treat active plaques with a topical corticosteroid of appropriate potency (often potent, given the thickness and itch), tapering as they settle',
      'Treat secondary bacterial infection (weeping/crusting/pustular) with antibiotics where indicated',
      'Use sedating antihistamines short-term if itch disturbs sleep (limited evidence for itch itself)',
      'Exclude tinea if there is any doubt (skin scrapings) before/while using steroids, as steroids worsen fungal infection',
      'For persistent or resistant disease, consider stronger topical therapy, occlusion, or dermatology referral (phototherapy/systemic options)',
      'Biopsy or refer a persistent solitary scaly plaque (especially on the lower leg in an older person) to exclude Bowen’s disease/skin cancer',
      'Provide an eczema self-care plan and review response'],
    referral:[
      'Diagnostic uncertainty, or a persistent solitary scaly plaque (possible Bowen’s/skin cancer) → dermatology (2WW if malignancy suspected — NICE NG12)',
      'Severe, widespread, or treatment-resistant disease → dermatology (phototherapy/systemic therapy)',
      'Recurrent secondary infection → review/treat',
      'Suspected tinea not responding → confirm with mycology'],
    source:'NICE CKS — Eczema (discoid)' },

  { id:'patellar-dislocation', title:'Dislocated kneecap (patellar dislocation)', category:'Musculoskeletal', icon:'🦵',
    overview:'Lateral displacement of the patella out of the trochlear groove, usually after a twisting injury or direct blow in a young, active person. Most reduce spontaneously or easily, but recurrent instability is common and some have associated osteochondral injury, so assessment and rehabilitation matter.',
    features:[
      'Acute knee pain with the kneecap visibly displaced laterally (if still dislocated), or a sensation that the knee "gave way" and "popped out then back"',
      'Rapid swelling (haemarthrosis), difficulty straightening/bearing weight, and apprehension on lateral pressure to the patella',
      'Mechanism: a twisting/pivoting movement on a planted foot, or a direct blow; commoner in young, active people and adolescents',
      'Predisposing factors: ligamentous laxity/hypermobility, shallow trochlea, high-riding patella, valgus alignment, and female sex',
      'Associated injuries: osteochondral fracture and medial patellofemoral ligament (MPFL) injury',
      'Diagnosis is clinical; X-ray after reduction to assess for fracture/loose body, with MRI for soft-tissue/osteochondral assessment as indicated'],
    management:[
      'If still dislocated, reduce promptly (gentle knee extension with medial pressure on the patella) with adequate analgesia — many reduce spontaneously',
      'After reduction: analgesia, X-ray to exclude osteochondral fracture/loose body, and assess neurovascular status',
      'Initial management: relative rest, ice, a brace/support for comfort and a short period of protected weight-bearing, then early physiotherapy',
      'Physiotherapy is central — quadriceps (especially VMO) and hip strengthening, and proprioceptive work to restore stability and prevent recurrence',
      'Refer for orthopaedic assessment if there is an osteochondral fragment/loose body, a first dislocation with significant injury, or recurrent instability',
      'Recurrent dislocations or persistent instability may need surgery (e.g. MPFL reconstruction)',
      'Address predisposing factors (alignment, hypermobility) and provide a graded return-to-activity plan',
      'Advise on the risk of recurrence and how to seek review'],
    referral:[
      'Osteochondral fracture/loose body, locked knee, or significant associated injury → urgent orthopaedics',
      'Irreducible dislocation or neurovascular compromise → emergency department',
      'Recurrent dislocation/persistent instability → orthopaedics (consider surgery)',
      'First dislocation → physiotherapy and routine orthopaedic/MSK review as indicated'],
    source:'NICE CKS / orthopaedic guidance' },

  { id:'shoulder-dislocation', title:'Dislocated shoulder', category:'Musculoskeletal', icon:'💪',
    overview:'Displacement of the humeral head from the glenoid — the most commonly dislocated major joint. Most are anterior, from a fall or sporting injury. Prompt reduction relieves pain and protects neurovascular structures; recurrence is common, especially in younger patients.',
    features:[
      'Severe shoulder pain after trauma, with the arm held slightly abducted/externally rotated (anterior) and an inability to move the joint',
      'Loss of the normal rounded shoulder contour (a "squared-off" shoulder) with a palpable gap below the acromion',
      'Anterior dislocation is by far the commonest; posterior dislocation is rarer and easily missed (consider after seizures or electric shock — the arm is held adducted/internally rotated)',
      'Assess axillary nerve function (sensation over the "regimental badge" area and deltoid) and the distal neurovascular status before and after reduction',
      'Associated injuries: greater tuberosity/glenoid fractures, rotator cuff tears (older patients), and Bankart/Hill-Sachs lesions',
      'Diagnosis: clinical plus X-ray (pre- and post-reduction) — including views to detect a posterior dislocation'],
    management:[
      'Provide prompt analgesia and arrange urgent assessment; most acute dislocations are reduced in the emergency department',
      'Confirm with X-ray and document neurovascular status (especially axillary nerve) before and after reduction',
      'Reduce promptly (with appropriate analgesia/sedation), then immobilise in a sling for a short period for comfort',
      'Arrange post-reduction X-ray to confirm reduction and exclude fracture',
      'Early physiotherapy to restore range, strength and proprioception, and to reduce recurrence',
      'Refer younger patients (high recurrence risk) and those with recurrent instability or significant associated injury (rotator cuff tear, fracture) to orthopaedics',
      'Suspect and X-ray adequately for posterior dislocation after seizures/electrocution',
      'Advise on recurrence risk and a graded return to activity/sport'],
    referral:[
      'Acute dislocation → emergency department for reduction (urgent if neurovascular compromise)',
      'Irreducible dislocation, fracture-dislocation, or neurovascular deficit → urgent orthopaedics',
      'Recurrent instability, or first dislocation in a young athlete → orthopaedics (consider stabilisation surgery)',
      'Suspected rotator cuff tear (older patient, persistent weakness) → orthopaedics/MSK'],
    source:'NICE CKS — Shoulder dislocation / BOAST guidance' },

  { id:'dissociative-disorders', title:'Dissociative disorders', category:'Mental health', icon:'🧠',
    overview:'A group of conditions involving a disruption of the normal integration of consciousness, memory, identity, emotion or perception — including dissociative amnesia, depersonalisation/derealisation, and dissociative identity disorder. They are strongly linked to psychological trauma and are diagnoses of exclusion after organic causes are ruled out.',
    features:[
      'Depersonalisation/derealisation: feeling detached from oneself or that the world is unreal/dreamlike, with intact reality testing',
      'Dissociative amnesia: an inability to recall important (usually traumatic/stressful) personal information, beyond ordinary forgetfulness',
      'Dissociative identity disorder: two or more distinct identity states with gaps in memory',
      'Often triggered by, or associated with, significant trauma, abuse, or acute stress; high comorbidity with PTSD, depression, anxiety and borderline personality disorder',
      'Overlap with functional neurological disorder (e.g. dissociative/non-epileptic seizures)',
      'Crucially, organic causes must be excluded (e.g. epilepsy, head injury, substance effects, delirium, other neurological disease) before diagnosis'],
    management:[
      'Take a careful history (including trauma and substance use) and exclude organic and other psychiatric causes — dissociative disorders are diagnoses of exclusion',
      'Validate the experience and explain dissociation as an understandable response to overwhelming stress/trauma; provide reassurance',
      'Ensure safety: assess risk (self-harm, suicide), and address any ongoing trauma/abuse and safeguarding',
      'Refer to mental-health services for assessment and trauma-focused psychological therapy, which is the mainstay of treatment',
      'There is no specific drug treatment for dissociation itself; treat comorbid depression, anxiety and PTSD on their own merits',
      'Promote grounding strategies and stabilisation, especially where dissociation is frequent/distressing',
      'Support function (work, relationships) and provide continuity of care',
      'Coordinate with neurology where there is overlap with functional neurological symptoms'],
    referral:[
      'Suspected dissociative disorder → mental-health services for assessment and psychological therapy',
      'Significant risk (self-harm/suicide) or acute crisis → urgent mental-health assessment',
      'Diagnostic uncertainty / possible organic cause → relevant investigation (e.g. neurology)',
      'Trauma/abuse or safeguarding concerns → appropriate support and safeguarding pathways'],
    source:'NICE CKS / trauma & mental-health guidance' },

  { id:'downs-syndrome', title:'Down’s syndrome (trisomy 21)', category:'Paediatrics', icon:'🧬',
    overview:'The commonest chromosomal cause of learning disability, due to trisomy 21. It is associated with characteristic features and a range of medical conditions across the lifespan. Care is about proactive surveillance for treatable associated conditions, supporting development, and respectful, person-centred care into adulthood.',
    features:[
      'Characteristic features: hypotonia, upslanting palpebral fissures, a flat nasal bridge, single palmar crease, and learning disability of variable degree',
      'Congenital and lifelong medical associations: congenital heart disease (e.g. AVSD), duodenal atresia/GI anomalies, hypothyroidism, hearing and vision problems, atlantoaxial instability, obstructive sleep apnoea, coeliac disease, and an increased risk of leukaemia in childhood',
      'In adulthood: earlier-onset Alzheimer’s disease, hypothyroidism, and other health needs',
      'Detected antenatally (combined/quad screening, NIPT, diagnostic testing) or postnatally (clinical features confirmed by karyotype)',
      'Wide variation in ability and health — individualise care and expectations',
      'Increased need for structured health surveillance throughout life'],
    management:[
      'Coordinate multidisciplinary, proactive care with structured surveillance for associated conditions (e.g. echocardiography in infancy, regular thyroid checks, hearing and vision testing, coeliac screening as indicated, and growth monitoring on Down-specific charts)',
      'Identify and treat congenital heart disease and other anomalies early via the relevant specialties',
      'Support development and learning with early intervention, therapies (SALT, OT, physiotherapy), and educational support',
      'Monitor for and manage common problems: hypothyroidism, sleep apnoea, ENT/hearing issues, and (be alert to) atlantoaxial instability and leukaemia',
      'Ensure immunisations and general child-health surveillance, and provide accessible, reasonable-adjustment care (avoid diagnostic overshadowing)',
      'Offer genetic counselling to the family and support transition to adult services',
      'In adults, watch for earlier cognitive decline/dementia, thyroid disease and mental-health needs, and support independence and capacity-appropriate decision-making',
      'Provide family support and signpost to specialist organisations'],
    referral:[
      'Suspected/confirmed Down’s syndrome → paediatrics + genetics, with onward referral for surveillance (cardiology, audiology, ophthalmology, etc.)',
      'Congenital heart disease or other anomaly → relevant specialty',
      'Features of leukaemia, atlantoaxial instability (neurology), or sleep apnoea → urgent/relevant assessment',
      'Adults: cognitive decline, thyroid or mental-health concerns → appropriate services'],
    source:'NICE CKS / Down’s syndrome health surveillance guidance' },

  { id:'dupuytrens', title:'Dupuytren’s contracture', category:'Musculoskeletal', icon:'✋',
    overview:'A benign fibroproliferative disorder of the palmar fascia causing nodules and cords that progressively flex the fingers (commonly the ring and little fingers) into the palm. It is slowly progressive and often bilateral; treatment is considered when contracture interferes with hand function.',
    features:[
      'Painless palmar nodules and thickening, then firm cords that tether and flex the affected fingers (most often the ring and little fingers)',
      'A positive "tabletop test" (the hand cannot be laid flat on a table) indicates significant contracture',
      'Slowly progressive, frequently bilateral; the metacarpophalangeal and proximal interphalangeal joints become flexed',
      'Risk factors: male sex, increasing age, northern European ancestry, family history, diabetes, alcohol excess, smoking, and antiepileptic use',
      'Associated "Dupuytren’s diathesis" features: knuckle pads, plantar (Ledderhose) and penile (Peyronie’s) fibromatosis — markers of more aggressive disease',
      'Diagnosis is clinical'],
    management:[
      'Reassure for early/mild disease (nodules without significant contracture) — observe, as not all progress; explain the natural history',
      'Address modifiable associations where relevant (alcohol, smoking, diabetes control)',
      'Monitor progression with the tabletop test and functional impact',
      'Refer for treatment when there is a functionally limiting contracture (e.g. MCP joint contracture ~30° or more, any significant PIP contracture, or the tabletop test becomes positive)',
      'Treatment options (specialist): needle fasciotomy, collagenase injection (availability varies), or surgical fasciectomy — choice depends on severity, joints involved and patient factors',
      'Hand therapy and splinting support recovery after intervention',
      'Counsel that recurrence is possible after treatment, especially with strong diathesis',
      'Provide information and arrange review of progression'],
    referral:[
      'Functionally significant contracture (positive tabletop test, MCP/PIP contracture limiting hand use) → hand surgery',
      'Rapidly progressive disease or strong diathesis → earlier specialist review',
      'Diagnostic uncertainty → hand specialist',
      'Recurrence after treatment → hand surgery'],
    source:'NICE CKS — Dupuytren’s disease' },

  { id:'dysentery', title:'Dysentery', category:'Infectious diseases', icon:'🦠',
    overview:'Inflammatory infective diarrhoea with blood and mucus, caused either by bacteria (e.g. Shigella, Campylobacter, invasive E. coli, Salmonella) or by the protozoan Entamoeba histolytica (amoebic dysentery). The priorities are rehydration, identifying the pathogen, judicious antibiotics, and public-health/notification duties.',
    features:[
      'Diarrhoea containing blood and mucus, with abdominal cramps, tenesmus, fever and malaise',
      'Bacillary (bacterial) dysentery: often acute and febrile (Shigella, Campylobacter, Salmonella, EHEC); EHEC (E. coli O157) risks haemolytic uraemic syndrome — avoid antibiotics and antimotility agents',
      'Amoebic dysentery: more gradual onset, travel to endemic areas, and a risk of liver abscess',
      'Risk/exposure clues: foreign travel, contaminated food/water, contacts with similar illness, and high-risk occupations (food handlers, healthcare, nursery/care work)',
      'Dehydration is the main acute danger, especially at the extremes of age',
      'Diagnosis: stool culture and microscopy (ova/cysts/parasites for amoeba), with attention to recent travel'],
    management:[
      'Assess and correct dehydration — oral rehydration first-line; IV fluids/admission for severe dehydration or inability to tolerate oral intake',
      'Send stool samples for culture and microscopy (and parasitology if amoebiasis is possible), noting travel and food history',
      'Most bacterial gastroenteritis is self-limiting and does not need antibiotics; use antibiotics selectively (e.g. severe illness, systemic involvement, specific pathogens, immunocompromise) per microbiology',
      'For suspected EHEC/E. coli O157, AVOID antibiotics and antimotility agents (they increase HUS risk) and monitor for HUS',
      'Treat confirmed amoebic dysentery with metronidazole (or tinidazole) followed by a luminal agent (e.g. diloxanide) to clear cysts; investigate for liver abscess if suspected',
      'Avoid antimotility drugs (e.g. loperamide) in bloody/inflammatory diarrhoea',
      'Apply exclusion advice (e.g. food handlers, healthcare/childcare workers off until 48 hours symptom-free, and per specific-pathogen rules) and hygiene measures',
      'Dysentery/specified pathogens are notifiable — inform public health'],
    referral:[
      'Severe dehydration, systemic sepsis, or inability to maintain hydration → admission',
      'Suspected haemolytic uraemic syndrome (oliguria, pallor, bruising, AKI — especially in children after E. coli O157) → emergency admission',
      'Suspected amoebic liver abscess or treatment failure → infectious diseases',
      'Notify public health (notifiable disease) and apply exclusion rules'],
    source:'UKHSA / NICE CKS — Gastroenteritis' },

  { id:'dyslexia', title:'Dyslexia', category:'Paediatrics', icon:'📖',
    overview:'A specific learning difficulty primarily affecting accurate and fluent word reading and spelling, arising from difficulties with phonological processing, despite adequate teaching and intelligence. It is common, persists into adulthood, and benefits from early identification and structured support to protect learning and self-esteem.',
    features:[
      'Difficulty with accurate/fluent reading and spelling out of keeping with the child’s overall ability and educational opportunity',
      'Problems with phonological awareness (linking letters and sounds), reading speed, and written spelling; reading is effortful',
      'Often: difficulty with sequencing, working memory, and rapid naming; may avoid reading and lose confidence',
      'A discrepancy between strong verbal/reasoning ability and written/reading performance is characteristic',
      'Frequently coexists with ADHD, developmental co-ordination disorder (dyspraxia), and speech/language difficulties',
      'Identification is educational/psychological (specialist assessment); it is not diagnosed by medical tests, but exclude sensory causes (vision/hearing)'],
    management:[
      'Exclude contributing sensory problems — check vision and hearing — and consider coexisting neurodevelopmental conditions',
      'Refer/liaise for specialist educational assessment (school SENCO, educational psychology, or specialist dyslexia assessment) to confirm and quantify needs',
      'Support is educational and structured: evidence-based, phonics-based, multisensory literacy intervention delivered by the school',
      'Reasonable adjustments and access arrangements: extra time, assistive technology (text-to-speech/speech-to-text), coloured overlays if helpful, and modified materials',
      'Protect self-esteem and mental wellbeing — emphasise strengths and address any anxiety or low mood',
      'Identify and support coexisting conditions (ADHD, dyspraxia)',
      'Provide information to families and signpost support organisations',
      'In adults, support workplace adjustments and access to assessment where relevant'],
    referral:[
      'Suspected dyslexia → school SENCO / educational psychology / specialist literacy assessment',
      'Coexisting neurodevelopmental concerns (ADHD, dyspraxia, speech/language) → relevant assessment',
      'Sensory concerns → optometry/audiology',
      'Associated mental-health difficulties → appropriate support'],
    source:'NICE CKS / educational & specific learning difficulty guidance' },

  { id:'dystonia', title:'Dystonia', category:'Neurology', icon:'🧠',
    overview:'A movement disorder of sustained or intermittent involuntary muscle contractions causing abnormal, often twisting, postures and repetitive movements. It ranges from focal (one body region, e.g. cervical dystonia, blepharospasm, writer’s cramp) to generalised, and may be primary/genetic or secondary — including the important drug-induced forms.',
    features:[
      'Sustained/intermittent muscle contractions producing twisting movements and abnormal postures, often action-specific and worsened by stress/fatigue',
      'A characteristic "sensory trick" (geste antagoniste) — touching the affected area can temporarily reduce the dystonia',
      'Focal types: cervical dystonia (spasmodic torticollis), blepharospasm (forced eye closure), oromandibular, laryngeal (spasmodic dysphonia), and task-specific (writer’s/musician’s cramp)',
      'ACUTE dystonic reaction: an acute, distressing drug-induced dystonia (e.g. after antipsychotics/antiemetics like metoclopramide/prochlorperazine) — often oculogyric crisis, torticollis, or tongue/jaw spasm',
      'Tardive dystonia: a delayed, often persistent dystonia from long-term dopamine-blocking drugs',
      'Secondary causes: drugs, Wilson’s disease (consider in young patients), Parkinson’s disease, cerebral palsy, and structural lesions; primary/genetic forms also occur'],
    management:[
      'Identify the type and any cause; take a careful drug history (dopamine-blocking antipsychotics/antiemetics) and consider secondary causes',
      'Treat an ACUTE dystonic reaction promptly with an anticholinergic (e.g. procyclidine IM/IV) and stop the offending drug — it is distressing but rapidly reversible',
      'In young patients with dystonia, exclude Wilson’s disease (it is treatable) and other secondary causes',
      'Refer to neurology/movement-disorder services for diagnosis and management of non-acute dystonia',
      'Focal dystonia: botulinum toxin injections are the treatment of choice (e.g. for cervical dystonia and blepharospasm), repeated periodically',
      'Oral medications (e.g. anticholinergics, others) and, for severe/generalised disease, deep brain stimulation are options under specialists; a dopa-responsive dystonia trial of levodopa is important not to miss',
      'Provide physiotherapy, supportive care, and psychological support; manage the functional and social impact',
      'Review and avoid culprit drugs; flag drug-induced dystonia in the record'],
    referral:[
      'Acute dystonic reaction → treat immediately (procyclidine) and stop the trigger; admit if airway/severe',
      'Non-acute/focal/generalised dystonia → neurology / movement-disorder service (for botulinum toxin, etc.)',
      'Young patient with dystonia → neurology (exclude Wilson’s disease and dopa-responsive dystonia)',
      'Severe/refractory or generalised dystonia → specialist (consider deep brain stimulation)'],
    source:'NICE CKS / movement disorder specialist guidance' }

  );
})();
